INSERT INTO practice_problems (title, description, difficulty, category, starter_code, solution_code, test_cases_json, points) VALUES
('Reverse a String', 'Write a function that reverses a string. The input string is given as an array of characters.', 'EASY', 'Algorithms', 'public class Solution {\n    public String reverseString(String s) {\n        // Write code here\n        return "";\n    }\n}', 'public class Solution {\n    public String reverseString(String s) {\n        return new StringBuilder(s).reverse().toString();\n    }\n}', '[{"input": "\"hello\"", "output": "\"olleh\""}, {"input": "\"Vikas\"", "output": "\"sakiV\""}]', 10),
('Two Sum', 'Given an array of integers nums and an integer target, return indices of the two numbers such that they add up to target.', 'MEDIUM', 'Data Structures', 'public class Solution {\n    public int[] twoSum(int[] nums, int target) {\n        // Write code here\n        return new int[]{};\n    }\n}', 'public class Solution {\n    public int[] twoSum(int[] nums, int target) {\n        java.util.Map<Integer, Integer> map = new java.util.HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        return new int[]{};\n    }\n}', '[{"input": "[2,7,11,15], 9", "output": "[0,1]"}, {"input": "[3,2,4], 6", "output": "[1,2]"}]', 20);
